37:   listener_.stats_.downstream_pre_cx_active_.dec();
38:   // If the underlying socket is no longer attached, it means that it has been transferred to
39:   // an active connection. In this case, the active connection will decrement the number
40:   // of listener connections.
41:   // TODO(mattklein123): In general the way we account for the number of listener connections
42:   // is incredibly fragile. Revisit this by potentially merging ActiveTcpSocket and
43:   // ActiveTcpConnection, having a shared object which does accounting (but would require
44:   // another allocation, etc.).
45:   if (socket_ != nullptr) {
46:     listener_.decNumConnections();
