84: void ActiveTcpSocket::createListenerFilterBuffer() {
85:   listener_filter_buffer_ = std::make_unique<Network::ListenerFilterBufferImpl>(
86:       socket_->ioHandle(), listener_.dispatcher(),
87:       [this](bool error) {
88:         (*iter_)->onClose();
89:         socket_->ioHandle().close();
90:         if (error) {
91:           listener_.stats_.downstream_listener_filter_error_.inc();
92:         } else {
93:           listener_.stats_.downstream_listener_filter_remote_close_.inc();
94:         }
95:         continueFilterChain(false);
96:       },
97:       [this](Network::ListenerFilterBufferImpl& filter_buffer) {
98:         Network::FilterStatus status = (*iter_)->onData(filter_buffer);
99:         if (status == Network::FilterStatus::StopIteration) {
100:           if (socket_->ioHandle().isOpen()) {
101:             // The listener filter should not wait for more data when it has already received
102:             // all the data it requested.
103:             ASSERT(filter_buffer.rawSlice().len_ < (*iter_)->maxReadBytes());
104:             // Check if the maxReadBytes is changed or not. If change,
105:             // reset the buffer capacity.
106:             if ((*iter_)->maxReadBytes() > filter_buffer.capacity()) {
107:               filter_buffer.resetCapacity((*iter_)->maxReadBytes());
108:               // Activate `Read` event manually in case the data already
109:               // available in the socket buffer.
110:               filter_buffer.activateFileEvent(Event::FileReadyType::Read);
111:             }
112:           } else {
113:             // The filter closed the socket.
114:             continueFilterChain(false);
115:           }
116:           return;
117:         }
118:         continueFilterChain(true);
119:       },
120:       (*iter_)->maxReadBytes() == 0, (*iter_)->maxReadBytes());
121: }
122: 
123: void ActiveTcpSocket::continueFilterChain(bool success) {
124:   if (success) {
125:     bool no_error = true;
126:     if (iter_ == accept_filters_.end()) {
127:       iter_ = accept_filters_.begin();
128:     } else {
129:       iter_ = std::next(iter_);
130:     }
131: 
132:     for (; iter_ != accept_filters_.end(); iter_++) {
133:       Network::FilterStatus status = (*iter_)->onAccept(*this);
134:       if (status == Network::FilterStatus::StopIteration) {
135:         // The filter is responsible for calling us again at a later time to continue the filter
136:         // chain from the next filter.
137:         if (!socket().ioHandle().isOpen()) {
138:           // Break the loop but should not create new connection.
139:           no_error = false;
140:           break;
141:         } else {
142:           // There are two cases for returning StopIteration. One is listener filter
143:           // needs to wait for data. The other is listener filter with 0 maxReadBytes()
144:           // doesn't inspect data, but needs to wait for some asynchronous callback and
145:           // listener filter buffer needs to listen for socket close event.
146:           if (listener_filter_buffer_ == nullptr) {
147:             createListenerFilterBuffer();
148:           }
149:           if ((*iter_)->maxReadBytes() > 0) {
150:             listener_filter_buffer_->disableOnDataCallback(false);
151:             // If the current filter expect more data than previous filters, then
152:             // increase the filter buffer's capacity.
153:             if (listener_filter_buffer_->capacity() < (*iter_)->maxReadBytes()) {
154:               listener_filter_buffer_->resetCapacity((*iter_)->maxReadBytes());
155:             }
156:             if (listener_filter_buffer_ != nullptr) {
157:               // There are two cases for activate event manually: One is
158:               // the data is already available when connect, activate the read event to peek
159:               // data from the socket . Another one is the data already
160:               // peeked into the buffer when previous filter processing the data, then activate the
161:               // read event to trigger the current filter callback to process the data.
162:               listener_filter_buffer_->activateFileEvent(Event::FileReadyType::Read);
163:             }
164:           } else {
165:             listener_filter_buffer_->disableOnDataCallback(true);
166:           }
167: 
168:           return;
169:         }
170:       }
171:     }
172:     // Successfully ran all the accept filters.
173:     if (no_error) {
174:       newConnection();
175:     } else {
176:       // Signal the caller that no extra filter chain iteration is needed.
177:       iter_ = accept_filters_.end();
178:     }
179:   }
180: 
181:   // Filter execution concluded, unlink and delete this ActiveTcpSocket if it was linked.
182:   if (inserted()) {
183:     unlink();
184:   }
185: }
