195: void ActiveTcpSocket::newConnection() {
196:   connected_ = true;
197: 
198:   // Check if the socket may need to be redirected to another listener.
199:   Network::BalancedConnectionHandlerOptRef new_listener;
200: 
201:   if (hand_off_restored_destination_connections_ &&
202:       socket_->connectionInfoProvider().localAddressRestored()) {
203:     // Find a listener associated with the original destination address.
204:     new_listener =
205:         listener_.getBalancedHandlerByAddress(*socket_->connectionInfoProvider().localAddress());
206:   }
207: 
208:   // Reset the file events which are registered by listener filter.
209:   // reference https://github.com/envoyproxy/envoy/issues/8925.
210:   if (listener_filter_buffer_ != nullptr) {
211:     listener_filter_buffer_->reset();
212:   }
213: 
214:   if (new_listener.has_value()) {
215:     // Hands off connections redirected by iptables to the listener associated with the
216:     // original destination address. Pass 'hand_off_restored_destination_connections' as false to
217:     // prevent further redirection.
218:     // Leave the new listener to decide whether to execute re-balance.
219:     // Note also that we must account for the number of connections properly across both listeners.
220:     // TODO(mattklein123): See note in ~ActiveTcpSocket() related to making this accounting better.
221:     listener_.decNumConnections();
222:     absl::optional<std::string> network_namespace;
223:     if (const auto* obj = stream_info_->filterState()->getDataReadOnlyGeneric(
224:             Network::DownstreamNetworkNamespace::key());
225:         obj) {
226:       network_namespace = obj->serializeAsString();
227:     }
228:     new_listener.value().get().onAcceptWorker(std::move(socket_), false, false, network_namespace);
229:   } else {
230:     // Set default transport protocol if none of the listener filters did it.
231:     if (socket_->detectedTransportProtocol().empty()) {
232:       socket_->setDetectedTransportProtocol("raw_buffer");
233:     }
234:     accept_filters_.clear();
235:     // Create a new connection on this listener.
236:     listener_.newConnection(std::move(socket_), std::move(stream_info_));
237:   }
238: }
239: } // namespace Server
240: } // namespace Envoy
