27: void ActiveStreamListenerBase::newConnection(Network::ConnectionSocketPtr&& socket,
28:                                              std::unique_ptr<StreamInfo::StreamInfo> stream_info) {
29:   // Find matching filter chain.
30:   const auto filter_chain = config_->filterChainManager().findFilterChain(*socket, *stream_info);
31:   if (filter_chain == nullptr) {
32:     RELEASE_ASSERT(socket->connectionInfoProvider().remoteAddress() != nullptr, "");
33:     ENVOY_LOG(debug, "closing connection from {}: no matching filter chain found",
34:               socket->connectionInfoProvider().remoteAddress()->asString());
35:     stats_.no_filter_chain_match_.inc();
36:     stream_info->setResponseFlag(StreamInfo::CoreResponseFlag::NoRouteFound);
37:     stream_info->setResponseCodeDetails(StreamInfo::ResponseCodeDetails::get().FilterChainNotFound);
38:     emitLogs(*config_, *stream_info);
39:     socket->close();
40:     return;
41:   }
42: 
43:   socket->connectionInfoProvider().setListenerInfo(config_->listenerInfo());
44:   socket->connectionInfoProvider().setFilterChainInfo(filter_chain->filterChainInfo());
45: 
46:   auto transport_socket = filter_chain->transportSocketFactory().createDownstreamTransportSocket();
47:   auto server_conn_ptr = dispatcher().createServerConnection(
48:       std::move(socket), std::move(transport_socket), *stream_info);
49:   if (const auto timeout = filter_chain->transportSocketConnectTimeout();
50:       timeout != std::chrono::milliseconds::zero()) {
51:     server_conn_ptr->setTransportSocketConnectTimeout(
52:         timeout, stats_.downstream_cx_transport_socket_connect_timeout_);
53:   }
54:   server_conn_ptr->setBufferLimits(config_->perConnectionBufferLimitBytes());
55:   RELEASE_ASSERT(server_conn_ptr->connectionInfoProvider().remoteAddress() != nullptr, "");
56:   const bool empty_filter_chain = !config_->filterChainFactory().createNetworkFilterChain(
57:       *server_conn_ptr, filter_chain->networkFilterFactories());
58:   if (empty_filter_chain) {
59:     ENVOY_CONN_LOG(debug, "closing connection from {}: no filters", *server_conn_ptr,
60:                    server_conn_ptr->connectionInfoProvider().remoteAddress()->asString());
61:     server_conn_ptr->close(Network::ConnectionCloseType::NoFlush, "no_filters");
62:   }
63:   newActiveConnection(*filter_chain, std::move(server_conn_ptr), std::move(stream_info));
64: }
