124: void OwnedActiveStreamListenerBase::removeConnection(ActiveTcpConnection& connection) {
125:   ENVOY_CONN_LOG(debug, "adding to cleanup list", *connection.connection_);
126:   ActiveConnections& active_connections = connection.active_connections_;
127:   ActiveConnectionPtr removed = connection.removeFromList(active_connections.connections_);
128:   dispatcher().deferredDelete(std::move(removed));
129:   // Delete map entry if and only if connections_ becomes empty.
130:   if (active_connections.connections_.empty()) {
131:     auto iter = connections_by_context_.find(&active_connections.filter_chain_);
132:     ASSERT(iter != connections_by_context_.end());
133:     // To cover the lifetime of every single connection, Connections need to be deferred deleted
134:     // because the previously contained connection is deferred deleted.
135:     dispatcher().deferredDelete(std::move(iter->second));
136:     // The erase will break the iteration over the connections_by_context_ during the deletion.
137:     if (!is_deleting_) {
138:       connections_by_context_.erase(iter);
139:     }
140:   }
141: }
