152: void OwnedActiveStreamListenerBase::removeFilterChain(const Network::FilterChain* filter_chain) {
153:   auto iter = connections_by_context_.find(filter_chain);
154:   if (iter == connections_by_context_.end()) {
155:     // It is possible when listener is stopping.
156:   } else {
157:     auto& connections = iter->second->connections_;
158:     while (!connections.empty()) {
159:       connections.front()->connection_->close(Network::ConnectionCloseType::NoFlush,
160:                                               "filter_chain_is_being_removed");
161:     }
162:     // Since is_deleting_ is on, we need to manually remove the map value and drive the
163:     // iterator. Defer delete connection container to avoid race condition in destroying
164:     // connection.
165:     dispatcher().deferredDelete(std::move(iter->second));
166:     connections_by_context_.erase(iter);
167:   }
168: }
